"""
MKT Christ — Luke all 24 chapters
Output: data/commentary/mkt-christ/luke.json
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "46": '<p>A type: the Magnificat. Mary\'s song is shaped by Hannah\'s prayer (1 Sam 2:1-10) — Hannah as the type of the Spirit-filled woman through whom the Lord\'s anointed enters the world. But the Magnificat exceeds Hannah\'s song: where Hannah praised for her personal vindication, Mary praises for the eschatological reversal that the incarnation initiates for all the humble and hungry of Israel and the world. The type (Hannah/Samuel) points to the antitype (Mary/Jesus) not as mere parallel but as fulfillment: what Hannah\'s prayer anticipated (the exaltation of the humble, the strength of the LORD\'s anointed) is now the content of the incarnation itself.</p>',
    "68": '<p>A fulfillment: blessed be the Lord God of Israel, for he has visited and redeemed his people. Zechariah\'s Benedictus identifies the births of John and Jesus as the visitation (episkope) of YHWH that all the prophets promised. The OT motif of divine visitation (YHWH visiting his people in mercy or judgment) reaches its fulfillment in the incarnation: God personally visits his people not through a prophet or angel but in the person of his Son. The redemption (lytrosis, v.68; lytrosan, v.74) is the Exodus-liberation pattern now applied to redemption from enemies (political) and from sin (spiritual), with both dimensions present.</p>'
  },
  "2": {
    "11": '<p>A direct revelation: a Savior, who is Christ the Lord, has been born for you in the city of David. The angelic announcement at the shepherds concentrates Luke\'s Christology in a single sentence. The Savior born in David\'s city is the fulfillment of the Davidic covenant, the messianic hope, and the divine rescue promised throughout the OT. Luke\'s characteristic soter (Savior) title connects Jesus to the salvation history of Israel (YHWH as Israel\'s only savior, Isa 43:11) while the details of the manger, the shepherds, and the town of Bethlehem anchor the salvation in the most ordinary and humble circumstances — the divine Savior in a feeding trough.</p>',
    "32": '<p>A fulfillment: a light for revelation to the Gentiles and for glory to your people Israel. Simeon\'s Nunc Dimittis applies the Isaianic Servant vocation (Isa 49:6) to the infant Jesus: he is the Servant who is a light to the nations. Luke\'s Gospel will be the narrative of this dual fulfillment — the glory of Israel (through the Jewish mission) and the light to the Gentiles (through the Gentile mission that Acts continues). The infant who cannot yet speak is already identified as the one in whom the universal Servant mission will be embodied and accomplished.</p>'
  },
  "4": {
    "18": '<p>A direct revelation: the Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. The Nazareth synagogue scene is Luke\'s programmatic statement of the Christological mission. Jesus reads Isa 61:1-2 and declares today this scripture has been fulfilled in your hearing (v.21) — the most explicit self-identification with the Isaianic Servant in the Synoptic Gospels. Luke presents the Christ\'s mission as the Jubilee: release to captives (from sin and from evil powers), sight to the blind, freedom for the oppressed, the year of the Lord\'s favor. The entire Gospel is the unfolding of this Jubilee-mission.</p>',
    "43": '<p>A direct revelation: I must preach the good news of the kingdom of God to the other towns as well; for I was sent for this purpose. The dei (it is necessary) of v.43 is one of Luke\'s most important theological terms — divine necessity shapes the mission at every point. Jesus was sent (apestalen) — the mission is not self-chosen but given by the Father. The kingdom of God that Jesus preaches is the reign of God becoming present in his own person; to hear Jesus is to encounter the kingdom\'s arrival.</p>'
  },
  "7": {
    "22": '<p>A fulfillment: go and tell John what you have seen and heard — the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Jesus\'s answer to the imprisoned John is the definitive self-identification from Isaiah: the signs that he lists are precisely the signs that Isaiah promised when YHWH comes to save (Isa 35:5-6, 61:1). Christ\'s identity is proven not by Messianic title-claim but by Isaianic sign-fulfillment; the question is not what do you claim to be? but what do you see happening? The works are the revelation.</p>'
  },
  "9": {
    "51": '<p>A direct revelation: when the days drew near for him to be taken up, he set his face to go to Jerusalem. Luke\'s travel-narrative framing (9:51-19:44) presents the entire journey to Jerusalem as a deliberate movement toward the passion, resurrection, and ascension. Jesus does not drift toward Jerusalem; he sets his face (Isa 50:7, the Servant who sets his face like flint to face opposition). Every parable and teaching in the travel narrative is colored by this deliberate journey toward the cross. The Christological claim is implicit: the one who moves with this resolve toward his own death is the one who has freely accepted the Father\'s mission from eternity.</p>'
  },
  "15": {
    "20": '<p>A revelation of God: the father of the prodigal son runs, embraces, and restores without condition. The father in the parable is transparently the image of God — no other first-century Jewish father would run (an undignified act) to embrace a disgraced son before any apology had been given. The parable is Jesus\'s defense of his own practice (receiving sinners) by revealing the Father\'s character: God himself is the running father who hosts the party for the found son and pleads with the older brother. Every feature of the father\'s excess (running, robe, ring, sandals, feast, self-humiliation at the party\'s edge) is a portrait of divine grace preceding, enabling, and exceeding human repentance.</p>'
  },
  "19": {
    "10": '<p>A direct revelation: the Son of Man came to seek and to save the lost. Luke\'s mission-statement frames the Zacchaeus encounter as the paradigmatic instance of the Son of Man\'s seeking-saving mission. The three parables of Luke 15 and the Zacchaeus narrative are the lived theology of Luke 19:10: the lost sheep sought by the shepherd, the lost coin sought by the woman, the lost son welcomed by the father, and now the lost Zacchaeus sought-and-found by the Son of Man himself. The mission of Luke\'s Gospel is the living-out of this one sentence, fulfilled supremely in the cross (where the Son of Man gives himself to save the utterly lost).</p>'
  },
  "22": {
    "20": '<p>A fulfillment: this cup that is poured out for you is the new covenant in my blood. Luke\'s cup-word (with the new covenant language from Jer 31:31-34) is the most explicit Jeremianic citation in the passion narratives. The new covenant — written on the heart, bringing forgiveness of sins, creating universal knowledge of YHWH — is inaugurated in the cup of Jesus\'s blood. The Passover context connects the new covenant blood to the Exodus blood (the lamb\'s blood that protected from the destroying angel): Christ\'s blood is simultaneously the final Passover (ending the old covenant\'s provisional atonement) and the new covenant\'s ratifying sacrifice.</p>',
    "37": '<p>A fulfillment: this scripture must be fulfilled in me: And he was numbered with the transgressors. Jesus\'s citation of Isa 53:12 before his arrest is the clearest evidence in the Synoptics that Jesus explicitly understood his death as the fulfillment of the Servant\'s vicarious suffering. The verb dei (must be fulfilled) indicates divine necessity: the Servant\'s path of bearing sin for the many was not merely predictive of his death but constitutive of the divine plan from which the cross received its saving power. The numbered-with-transgressors (arrested as a criminal) is the humiliation that precedes the Servant\'s exaltation.</p>'
  },
  "23": {
    "43": '<p>A direct revelation: today you will be with me in paradise. The word to the penitent criminal is the most compressed eschatological promise in the Gospels: today (the dying day, no purgatorial delay), with me (personal presence with Christ, not merely a blessed state), in paradise (the garden-restored, the original Eden-with-God now restored). The dying Christ who is in the process of bearing sin for the many simultaneously promises the thief immediate eschatological fellowship. The promise grounds the community\'s confidence: if even the dying criminal is welcomed today, the resurrection-hope of all who trust Christ is secured.</p>',
    "46": '<p>A direct revelation: Father, into your hands I commit my spirit. Luke\'s Christ dies with Ps 31:5 as his final prayer — the trust-language of the righteous sufferer who commits himself to the faithful Father at death. The Father-address maintains the intimate relationship that defined the whole of Luke\'s Christological portrayal (Abba in Gethsemane, 22:42; this prayer at death). The Spirit commended to the Father\'s hands is the Spirit that will be poured out at Pentecost (Acts 2) — even in death the Son\'s Spirit remains in the Father\'s keeping, to be given back in the resurrection and then poured out on the community.</p>'
  },
  "24": {
    "27": '<p>A direct revelation: beginning with Moses and all the Prophets he interpreted to them in all the Scriptures the things concerning himself. The risen Christ\'s Emmaus hermeneutic is the epistemological key to Luke\'s entire Gospel: the OT is about Christ, and only the risen Christ can unlock its true meaning. The burning hearts (v.32) indicate that proper reading of Scripture is simultaneously encounter with the risen Christ — not merely information about him but the experience of his presence through the word. Luke\'s Gospel has been narrating what the risen Christ explained: the whole story of Israel (from Genesis through the Prophets) was the long preparation for and anticipation of what Jesus accomplished in Jerusalem.</p>',
    "46": '<p>A direct revelation: it is necessary that the Christ should suffer and on the third day rise from the dead, and that repentance for the forgiveness of sins should be proclaimed in his name to all nations. The risen Christ\'s final hermeneutical statement to the disciples declares the canonical shape of the Christological narrative: suffering → resurrection is the divinely necessary arc (dei), and the worldwide mission to proclaim forgiveness in his name is its equally necessary consequence. Luke 24:46-47 is the theological thesis of Acts, which will narrate exactly this proclamation going from Jerusalem to the ends of the earth. The Christ\'s mission is complete; the community\'s mission is just beginning.'
  }
}

# Gap-fill ch 6 — all 49 verses
FILL_CH6 = {
  "6": {
    "1": "<p>The grain-field Sabbath controversy opens the section of escalating conflict over Jesus&#8217;s authority. The disciples rubbing grain echoes the gleaners&#8217; right (Deut 23:25) and the Sabbath provision of manna (Exod 16). Jesus&#8217;s appeal to David sets up the Christological argument: as David had authority over the Tabernacle bread (1 Sam 21:1&#8211;6), so the Son of David has authority over the Sabbath itself &#8212; a theme-level identification of Jesus with David&#8217;s greater heir.</p>",
    "2": "<p>The Pharisees&#8217; accusation (&#8220;why are you doing what is unlawful on the Sabbath?&#8221;) treats the Sabbath as an absolute legal boundary beyond which even hunger cannot cross. Their challenge is the foil for Jesus&#8217;s self-revelation in v.5: the Pharisees defend the Sabbath as God&#8217;s immovable law; Jesus reveals that the Son of Man is Lord over that law. The confrontation demonstrates the theme of Jesus&#8217;s authority exceeding the received religious framework of Israel.</p>",
    "3": "<p>Jesus cites 1 Sam 21:1&#8211;6 (David and the shewbread) as a hermeneutical precedent. The argument is typological: David&#8217;s necessity overrode the bread&#8217;s priestly restriction; the Son of David&#8217;s presence overrides the Sabbath restriction. The appeal to David also signals Jesus&#8217;s Davidic identity &#8212; he is not merely evoking a legal precedent but identifying himself as the fulfillment of the Davidic type. Greater than David, he has authority that David only prefigured.</p>",
    "4": "<p>David ate the consecrated bread reserved for priests &#8212; a type of Christ, the one high priest who fulfills and supersedes the entire priestly system (Heb 4:14&#8211;16; 7:27). Just as the bread of the presence was reserved for priests, yet David&#8217;s need overrode the restriction, so Christ&#8217;s priesthood fulfills what the temple bread represented: the bread of the presence (his body) is now given freely to all who come to him in hunger (John 6:35).</p>",
    "5": "<p>&#8220;The Son of Man is Lord of the Sabbath&#8221; &#8212; a direct Christological claim. Lord (<em>kyrios</em>) of the Sabbath is Lord of the day that YHWH himself rested and sanctified (Gen 2:2&#8211;3; Exod 20:11). Jesus is claiming divine sovereignty over the institution that revealed God&#8217;s rest at creation. The Sabbath rest is a type of the eschatological rest that Christ provides (Heb 4:9&#8211;11: &#8220;there remains a Sabbath-rest for the people of God&#8221;), and Christ as Lord of the Sabbath is the one who provides it.</p>",
    "6": "<p>The man with the shriveled hand in the synagogue is a type of Israel &#8212; the covenant people hampered in their work (bearing fruit for God) by a condition they cannot heal. The synagogue setting frames the healing as a public, official confrontation: the cure happens in the place of Torah-study, before the guardians of the law. Christ&#8217;s healing in the synagogue on the Sabbath is the in-breaking of the kingdom into the very place where Israel should have been awaiting it.</p>",
    "7": "<p>The Pharisees&#8217; watching to find a reason to accuse is the hardened-heart pattern of Isa 6:9&#8211;10: they see and do not perceive, hear and do not understand. Their observation of the healing as a legal violation rather than a sign of divine mercy demonstrates the perversion of the covenant: the law given to protect life has become a framework for opposing the source of life. The opposition that Christ faces from guardians of the law anticipates the trial-and-passion narrative.</p>",
    "8": "<p>&#8220;Jesus knew what they were thinking&#8221; &#8212; the divine knowledge of hidden thoughts is a divine attribute (1 Kgs 8:39; Ps 139:2; Jer 17:10). Christ&#8217;s command to the man (&#8220;get up and stand in front of everyone&#8221;) makes the healing a public, unambiguous act that cannot be dismissed as private or accidental. He forces the issue into the open, demonstrating that his intention is to heal and his authority is undeniable &#8212; the revelation is deliberate and confrontational.</p>",
    "9": "<p>&#8220;Which is lawful on the Sabbath: to do good or to do evil, to save life or to destroy it?&#8221; &#8212; Jesus reframes the Sabbath question around the nature of God himself. God&#8217;s rest on the Sabbath is the rest of the life-giver, not of an idle deity; the Sabbath rest is for life, not death. Jesus as Lord of the Sabbath is the one who defines the Sabbath&#8217;s purpose &#8212; and his silence-demanding question reveals the religious leaders as preferring the destruction of life to its rescue.</p>",
    "10": "<p>&#8220;Stretch out your hand. He did so, and his hand was completely restored&#8221; &#8212; the restoration of the withered hand is the immediate response to Jesus&#8217;s authoritative word. The word alone heals: as in the creation narratives (God speaks and it is so, Gen 1), Jesus&#8217;s word accomplishes what it commands. The healing is a type of the new creation that Christ brings through his word &#8212; the withered, damaged human capacity restored to full function by the creative authority of the Creator himself present in human form.</p>",
    "11": "<p>The religious leaders&#8217; fury and scheming against Jesus &#8212; immediately after a healing &#8212; reveals the depth of the hardening. The contrast is stark: a man&#8217;s hand has just been restored to wholeness, and the response is plotting for Jesus&#8217;s destruction. This irony (life given, death plotted) is the pattern of the passion: Jesus gives his life for others and the authorities plot to destroy him. The Sabbath healings are the microcosm of the cross &#8212; the Lord of life condemned by those who guard the institutions of life.</p>",
    "12": "<p>Jesus spending the night in prayer before choosing the Twelve reflects the divine deliberateness of the apostolic constitution. The mountain prayer echoes Moses on Sinai (Exod 24:12&#8211;18; 34:2) and Elijah at Horeb (1 Kgs 19:8&#8211;12) &#8212; the mountain as the place of divine encounter. Jesus as the new Moses descends from the mountain to constitute the new covenant community; the all-night prayer indicates that the Twelve are chosen by the Father&#8217;s will revealed through prayer, not merely human selection.</p>",
    "13": "<p>The choosing of twelve apostles is a direct Christological action: the number twelve reconstitutes Israel (twelve tribes/patriarchs; cf. Matt 19:28, &#8220;you will sit on twelve thrones, judging the twelve tribes of Israel&#8221;). Jesus as the new Moses (the greater prophet, Deut 18:15&#8211;18) constitutes the new covenant community around himself. The apostles (<em>apostoloi</em>, sent ones) will be sent as he was sent &#8212; participating in the Son&#8217;s mission from the Father (John 20:21).</p>",
    "14": "<p>Simon (named Peter, &#8220;rock&#8221;) is the first of the Twelve. The name-change is a type of the patriarchal name-changes (Abram to Abraham, Jacob to Israel) that signal a new covenantal identity. Peter&#8217;s leadership among the apostles and his confession of Christ (9:20) will make him the foundational figure of the early church (Acts 1&#8211;12), a shadow of Christ as the true foundation stone (1 Cor 3:11; Isa 28:16). Andrew, James, and John are the inner circle of witnesses for the Transfiguration and Gethsemane.</p>",
    "15": "<p>The apostolic list continues: Matthew (the toll-collector, implying the call of the marginal), Thomas, James son of Alphaeus, and Simon the Zealot. The combination of Matthew (a tax-collector collaborating with Rome) and Simon the Zealot (opposing Rome) in the same apostolic band is a type of the new creation&#8217;s social reconciliation &#8212; the kingdom of God draws together those the world keeps divided. Christ&#8217;s peace (Eph 2:14&#8211;16) is demonstrated in the diversity of his chosen community.</p>",
    "16": "<p>Judas Iscariot, who became a traitor, is included in the original Twelve by divine foreknowledge. The betrayal is not an accident or a divine plan gone wrong; it fulfills Ps 41:9 (&#8220;even my close friend, someone I trusted, one who shared my bread, has lifted his heel against me&#8221;, cited in John 13:18). The inclusion of Judas in the Twelve demonstrates that Christ chose him with full knowledge of his betrayal &#8212; the cross was always the goal, and the betrayer&#8217;s role was known from the foundation.</p>",
    "17": "<p>Jesus coming down from the mountain to a level place with the Twelve and meeting a large crowd mirrors Moses descending Sinai (Exod 34:29): the lawgiver comes down from the mountain of divine encounter to the people. The crowd from &#8220;the whole region of Judea and Jerusalem and the seacoast of Tyre and Sidon&#8221; (Gentile territory) anticipates the universal reach of the gospel &#8212; the new Moses brings the new law to a gathering that transcends Israel&#8217;s ethnic boundaries.</p>",
    "18": "<p>&#8220;Those troubled by impure spirits were cured&#8221; &#8212; the healing of disease and the exorcism of impure spirits are aspects of the single liberation that the Servant-Isaiah promised (Isa 53:4&#8211;5: &#8220;he took up our infirmities and bore our diseases&#8221;). Matthew 8:17 cites Isa 53:4 explicitly as the fulfillment of Jesus&#8217;s healing ministry. The healings are the bodily foretaste of the full resurrection-restoration that Christ&#8217;s atoning work secures (Rev 21:4: &#8220;he will wipe every tear from their eyes; there will be no more death or mourning or crying or pain&#8221;).</p>",
    "19": "<p>&#8220;Power was coming from him and healing them all&#8221; &#8212; the <em>dynamis</em> (power) going out from Jesus is the same word used for the Spirit&#8217;s power in 1:35 and 4:14; the power that constituted Jesus at the Annunciation and the baptism is now being given to others through contact with him. The image of divine power flowing from a person echoes the Spirit&#8217;s presence in Ezekiel&#8217;s vision (Ezek 47:1&#8211;12): the river of life flowing from the Temple. Christ is the living Temple from whom the healing river flows.</p>",
    "20": "<p>The Lukan Beatitudes are addressed directly to the disciples (&#8220;looking at his disciples, he said&#8221;), making them the Sermon on the Plain&#8217;s new covenant charter for the community. &#8220;Blessed are you who are poor, for yours is the kingdom of God&#8221; fulfills Isa 61:1 (&#8220;good news to the poor&#8221;) &#8212; the Jubilee proclamation Jesus claimed in 4:18. The kingdom belonging to the poor is a direct Christological promise: Christ who became poor (2 Cor 8:9) brings the kingdom to those who have nothing to offer.</p>",
    "21": "<p>&#8220;Blessed are you who hunger now, for you will be satisfied&#8221; fulfills the promise of Ps 107:9 (&#8220;he satisfies the thirsty and fills the hungry with good things&#8221;) and Isa 55:1&#8211;2 (&#8220;come, all you who are thirsty&#8221;). Christ as the bread of life (John 6:35: &#8220;whoever comes to me will never go hungry; whoever believes in me will never be thirsty&#8221;) is the agent of this filling. The weeping-to-laughter reversal echoes Ps 126:5&#8211;6 (&#8220;those who sow in tears will reap with songs of joy&#8221;) &#8212; the eschatological reversal that Christ&#8217;s resurrection initiates.</p>",
    "22": "<p>&#8220;Blessed are you when people hate you, exclude you, insult you and reject your name as evil, because of the Son of Man&#8221; &#8212; persecution endured because of the Son of Man is participation in his own rejection. The Son of Man who came to his own (John 1:11), was &#8220;despised and rejected&#8221; (Isa 53:3), bears the disciples&#8217; rejection forward. The beatitude transforms suffering into eschatological blessing: sharing in the rejected Christ&#8217;s fate is sharing in his vindicated glory (Rom 8:17: &#8220;if we share in his sufferings we may also share in his glory&#8221;).</p>",
    "23": "<p>&#8220;Rejoice in that day and leap for joy, because great is your reward in heaven&#8221; &#8212; the eschatological joy of the persecuted community grounds the ethics of the Beatitudes. The reference to &#8220;how their ancestors treated the prophets&#8221; places the disciples in the line of the prophets &#8212; who were rejected before being vindicated. Christ himself is the rejected prophet (Luke 4:24; 13:33) who becomes the exalted Lord; the disciples&#8217; rejection follows his pattern and participates in his eventual vindication.</p>",
    "24": "<p>The woe to the rich (&#8220;you have already received your comfort&#8221;) is the Lukan counter-beatitude: those who receive their consolation in the present age will find none in the eschatological age of reversal. The word &#8220;comfort&#8221; (<em>paraklēsis</em>) is the same root as the Paraclete (Helper/Comforter, John 14:16) &#8212; those who receive earthly comfort in place of the Paraclete have traded the eternal comfort of Christ&#8217;s Spirit for a temporary substitute. The woe is Christ&#8217;s warning about the ultimate priority of the kingdom over all worldly wealth.</p>",
    "25": "<p>&#8220;Woe to you who are well fed now, for you will go hungry; woe to you who laugh now, for you will mourn and weep&#8221; &#8212; the great reversal of the Magnificat (1:52&#8211;53: &#8220;he has filled the hungry with good things but has sent the rich away empty&#8221;) becomes the ethical framework for the Beatitudes. The eschatological hunger of those presently satisfied is not punitive cruelty but the logical outcome of refusing the bread of life: those who are full of this age&#8217;s food will find no room for the feast Christ provides.</p>",
    "26": "<p>&#8220;Woe to you when everyone speaks well of you, for that is how their ancestors treated the false prophets&#8221; &#8212; the final woe is about the approval of the crowd. Christ himself was spoken well of before his rejection (4:22); popularity is not validation. The theme of the rejected true prophet versus the accepted false prophet runs from Jer 5:31 through the passion: Jesus is condemned by the crowd while Barabbas is released (23:18&#8211;25). Christ&#8217;s followers who are universally praised should examine whether they are actually proclaiming him.</p>",
    "27": "<p>&#8220;Love your enemies&#8221; &#8212; the command that exceeds all previous ethical frameworks. This is not merely a higher morality but a revelation of the character of God: the Father loves his enemies (v.35: &#8220;he is kind to the ungrateful and wicked&#8221;), and Christ is the embodiment of that love (Rom 5:10: &#8220;while we were enemies, we were reconciled to God through the death of his Son&#8221;). The ethics of enemy-love are grounded in the incarnation and the cross &#8212; not abstract principles but the concrete love Christ demonstrates for his enemies.</p>",
    "28": "<p>&#8220;Bless those who curse you, pray for those who ill-treat you&#8221; &#8212; the pattern Jesus himself will follow: blessing from the cross (23:34, &#8220;Father, forgive them, for they do not know what they are doing&#8221;) and Stephen at his stoning (Acts 7:60). The command is not self-generated moral heroism but participation in Christ&#8217;s own pattern of response to suffering. To bless those who curse is to enact the cross &#8212; to absorb hostility and return grace, following the One who absorbed the world&#8217;s hostility on Calvary.</p>",
    "29": "<p>&#8220;If someone slaps you on one cheek, turn to them the other also&#8221; &#8212; the radical non-retaliation that Christ himself practices before Pilate and at the cross. The theme of absorbing violence and returning non-violence is the Servant&#8217;s posture in Isa 50:6 (&#8220;I offered my back to those who beat me, my cheeks to those who pulled out my beard; I did not hide my face from mocking and spitting&#8221;). The disciple&#8217;s non-retaliation participates in the pattern of Christ&#8217;s voluntary self-offering.</p>",
    "30": "<p>&#8220;Give to everyone who asks you, and if anyone takes what belongs to you, do not demand it back&#8221; &#8212; the radical generosity that reflects the Father&#8217;s character of unrestricted giving. The theme finds its Christological grounding in 2 Cor 8:9: &#8220;though he was rich, yet for your sake he became poor, so that you through his poverty might become rich.&#8221; Christ&#8217;s self-giving without condition or repayment is the model; the disciple who gives without demanding return enacts the same logic of grace.</p>",
    "31": "<p>&#8220;Do to others as you would have them do to you&#8221; &#8212; the golden rule summarizes the law and prophets (Matt 7:12). In Christ&#8217;s mouth, this is not merely ethical reciprocity but the revelation of the Father&#8217;s nature. God treats us as he would have us treat him &#8212; with love that does not depend on our response. Christ as the fulfillment of the law (Matt 5:17) embodies the golden rule perfectly: he treats every human being as he wishes the Father to treat himself, with absolute faithfulness and love regardless of response.</p>",
    "32": "<p>&#8220;If you love those who love you, what credit is that to you? Even sinners love those who love them&#8221; &#8212; the distinguishing mark of the kingdom community is love that exceeds natural reciprocity. The <em>charis</em> (credit/grace) that Jesus invokes is the same word for grace: it is a grace-based community, not a merit-exchange community. Christ&#8217;s love for those who hate him (Rom 5:8; John 15:13) is the baseline that exposes the inadequacy of love-for-love; his love is the cause and pattern of the disciple&#8217;s love for enemies.</p>",
    "33": "<p>The second element (doing good to those who do good to you): even the wicked operate on this exchange principle. Christ&#8217;s call is to transcend the reciprocity system entirely &#8212; not because the system is intrinsically wrong but because it cannot represent the kingdom&#8217;s economy of grace. The theme of transcending natural exchange is at the heart of the atonement: Christ does good to those who do evil to him, breaking the retribution cycle through his self-sacrifice (1 Pet 2:23: &#8220;when he suffered, he made no threats&#8221;).</p>",
    "34": "<p>&#8220;If you lend to those from whom you expect repayment, what credit is that to you?&#8221; &#8212; lending with expectation of return is the financial shadow of the Pharisees&#8217; transactional righteousness. The kingdom economy is the economy of grace: give without calculating return. The Jubilee background (Lev 25:35&#8211;37, lending to the poor without interest) grounds this command in the covenant. Christ himself is the Jubilee-lender: he gives his life without any prospect of repayment from those who receive it, the ultimate expression of uncalculating generosity.</p>",
    "35": "<p>&#8220;Love your enemies, do good to them, and lend to them without expecting to get anything back. Then your reward will be great, and you will be children of the Most High, because he is kind to the ungrateful and wicked.&#8221; This is the ground of the ethic: God&#8217;s character. The Father&#8217;s kindness to the ungrateful and wicked is the revelation of God that the cross makes explicit (Rom 5:8). To love enemies is to be a child of the Father who loved his enemies in Christ. The reward is not the point; sonship &#8212; participation in the Father&#8217;s character &#8212; is.</p>",
    "36": "<p>&#8220;Be merciful, just as your Father is merciful&#8221; &#8212; the summary command of the Sermon on the Plain and the revelation of God at the center of Jesus&#8217;s ethics. The Father&#8217;s mercy (<em>oiktirmōn</em>) is the character that Christ embodies (Heb 2:17: &#8220;a merciful and faithful high priest&#8221;; 4:15: &#8220;sympathize with our weaknesses&#8221;) and the cross demonstrates. To call God &#8220;merciful&#8221; (<em>rahum</em>, the divine attribute proclaimed in Exod 34:6&#8211;7 at Sinai) in the context of disciple-formation is to say: the character revealed in the Exodus is now incarnate in Christ and to be formed in you.</p>",
    "37": "<p>&#8220;Do not judge, and you will not be judged; do not condemn, and you will not be condemned; forgive, and you will be forgiven&#8221; &#8212; the three commands rest on the same mercy principle (v.36). The theme of non-judgment runs from the Sermon to the passion: Christ does not condemn those who condemn him (John 3:17: &#8220;God did not send his Son into the world to condemn the world but to save the world through him&#8221;). The one who has the authority to judge all (John 5:22) withholds judgment in the incarnation, taking the judgment himself at the cross.</p>",
    "38": "<p>&#8220;Give, and it will be given to you. A good measure, pressed down, shaken together and running over, will be poured into your lap&#8221; &#8212; the abundance of the kingdom&#8217;s return exceeds any giving we can offer. The image of the overflowing measure echoes Mal 3:10 (&#8220;bring the whole tithe&#8230; and see if I will not throw open the floodgates of heaven and pour out so much blessing that there will not be room enough to store it&#8221;). Christ as the giver of all good gifts (Jas 1:17; John 3:16) is the source of the abundance that exceeds all giving.</p>",
    "39": "<p>&#8220;Can the blind lead the blind? Will they not both fall into a pit?&#8221; &#8212; the parable challenges the Pharisees as blind guides (Matt 15:14; 23:16). But Christologically, Jesus is the light of the world who gives sight to the blind (John 9:5; Isa 42:7), the only one who can lead because he can see. The disciple&#8217;s formation depends on being led by the one teacher who is not blind &#8212; Christ himself, the one who has seen the Father (John 1:18) and can lead his disciples toward the Father.</p>",
    "40": "<p>&#8220;The student is not above the teacher, but everyone who is fully trained will be like their teacher&#8221; &#8212; a theme of Christological formation. The disciples&#8217; goal is to be like their teacher Jesus &#8212; not merely to know his teaching but to be conformed to his character (Rom 8:29: &#8220;conformed to the image of his Son&#8221;; Phil 3:10&#8211;11). The teacher whose likeness disciples will bear is the one who embodies perfect obedience, mercy, and love; formation in Christ is formation in the image of the eternal Son.</p>",
    "41": "<p>&#8220;Why do you look at the speck in your brother&#8217;s eye but do not notice the plank in your own?&#8221; &#8212; the hypocrisy parable exposes the self-deceived judge. Christologically, this verse reveals the nature of self-righteousness &#8212; the inability to see one&#8217;s own sin while scrutinizing others&#8217;. Christ as the sinless one is the only one who genuinely sees &#8212; yet he does not use his sight to condemn (John 8:11) but to heal. His cross removes the plank from our eye (the guilt that distorts our vision) before he addresses the speck in others.</p>",
    "42": "<p>&#8220;You hypocrite! First take the plank out of your own eye, and then you will see clearly to remove the speck from your brother&#8217;s eye&#8221; &#8212; the correction of hypocrisy is not an end to correction but the ordering of it. Christ who &#8220;became sin for us&#8221; (2 Cor 5:21) removes the ultimate plank &#8212; our guilt before God &#8212; through his atonement, enabling his disciples to offer genuine correction from a position of honest self-knowledge rather than self-righteousness. The cross is the precondition for all authentic pastoral correction in the community.</p>",
    "43": "<p>&#8220;No good tree bears bad fruit, nor does a bad tree bear good fruit&#8221; &#8212; the tree-and-fruit principle is a theme of Christological judgment applied to the community. Christ is the good tree &#8212; he produces perfectly good fruit (John 15:5 uses the same botanical metaphor: &#8220;I am the vine; you are the branches&#8221;). Fruitfulness is not self-generated; it depends on union with the life-source. Bad fruit reveals a bad root; good fruit reveals connection to the good root &#8212; ultimately to Christ himself as the source of all genuine goodness.</p>",
    "44": "<p>&#8220;Each tree is recognized by its own fruit. People do not pick figs from thorn-bushes or grapes from briers&#8221; &#8212; Jeremiah&#8217;s oracle (Jer 17:8&#8211;10) provides the background: the one who trusts in the Lord is like a tree planted by water, bearing fruit in season. The Christological application: Christ as the living water (John 4:14; 7:37&#8211;38) is the source beside which the true disciple is planted. Those who bear thorn-and-brier fruit are the false teachers and leaders who draw their life from elsewhere than from Christ.</p>",
    "45": "<p>&#8220;A good man brings good things out of the good stored up in his heart&#8221; &#8212; the treasure of the heart determines the speech and action that flow from it. The theme of the heart&#8217;s transformation is the new covenant promise (Jer 31:33; Ezek 36:26): the law written on the heart produces obedience from the inside rather than external compliance. Christ as the fulfillment of the new covenant is the one who transforms the heart through the Spirit (2 Cor 3:3; Col 3:16: &#8220;let the word of Christ dwell richly in you&#8221;); out of the Christ-formed heart flows good treasure.</p>",
    "46": "<p>&#8220;Why do you call me &#8216;Lord, Lord,&#8217; and do not do what I say?&#8221; &#8212; the challenge of misplaced confession is a direct Christological warning. The title <em>Kyrios</em> (Lord) applied to Jesus is the LXX&#8217;s rendering of YHWH; to call him Lord without obedience is to acknowledge his divine identity while refusing its claim. Christ as Lord demands the obedience of the heart (Rom 10:9: &#8220;if you confess with your mouth, &#8216;Jesus is Lord,&#8217; and believe in your heart&#8230;&#8221;). Verbal confession without transformed life is not the new covenant&#8217;s faith.</p>",
    "47": "<p>&#8220;As for everyone who comes to me and hears my words and puts them into practice, I will show you what they are like&#8221; &#8212; the foundation parable begins with coming to Christ as the source of the words. The Christological center is &#8220;comes to me&#8221; &#8212; not merely &#8220;hears the teaching&#8221; but personal encounter with the teacher. Christ as the word of God (John 1:1) and the one through whom the Father&#8217;s will is known (John 14:6: &#8220;I am the way, the truth, and the life&#8221;) is both the foundation and the teacher who builds upon it.</p>",
    "48": "<p>&#8220;They are like a man building a house who dug down deep and laid the foundation on rock&#8221; &#8212; a direct Christological type: Christ is the rock foundation (1 Cor 3:11: &#8220;no one can lay any foundation other than the one already laid, which is Jesus Christ&#8221;; Isa 28:16: &#8220;a precious cornerstone for a sure foundation&#8221;). The deep digging represents the costly work of hearing and obeying &#8212; the cross-formed life that goes below the surface to build on the indestructible foundation. The flood that could not shake the house is the eschatological judgment that the Christ-built life withstands.</p>",
    "49": "<p>&#8220;But the one who hears my words and does not put them into practice is like a man who built a house without a foundation: the moment the torrent struck that house, it collapsed and its destruction was complete&#8221; &#8212; the shadow of judgment falls over the sermon&#8217;s close. The house without foundation is the life built on anything other than Christ. The complete destruction at the flood corresponds to the eschatological judgment that every life must face (1 Cor 3:13: &#8220;their work will be shown for what it is, because the Day will bring it to light&#8221;). Christ as foundation is the only protection against total collapse.</p>"
  }
}

# Gap-fill ch 7 — all verses except v22 (already in DATA)
FILL_CH7 = {
  "7": {
    "1": "<p>&#8220;When Jesus had finished saying all this to the people who were listening, he entered Capernaum&#8221; &#8212; the transition from the Sermon on the Plain to the healing of the centurion&#8217;s servant. The movement from teaching to healing enacts the Servant&#8217;s dual mission: to proclaim and to act. Capernaum as &#8220;his own city&#8221; (Matt 9:1) is the base of the Galilean ministry &#8212; and the site where, by the end of the Gospel, Jesus will have done many of his works (10:15, the woe against Capernaum&#8217;s unbelief).</p>",
    "2": "<p>The centurion&#8217;s servant who is &#8220;dear to him&#8221; (<em>entimos</em>, highly valued/honored) is the first Gentile healing in Luke&#8217;s Gospel. The social situation &#8212; a Roman military officer seeking healing for a slave &#8212; crosses the boundaries of both ethnicity and social class. The centurion&#8217;s care for his servant demonstrates a humanity that transcends expected Roman treatment of slaves and anticipates the reversal of social hierarchies in the kingdom Christ proclaims.</p>",
    "3": "<p>The centurion sending Jewish elders as intermediaries demonstrates the honor-shame dynamic: he considers himself unworthy to approach Jesus directly (v.6). Yet the very indirection of his approach reflects the extraordinary faith Jesus will praise in v.9: the centurion believes that Jesus&#8217;s authority does not depend on his physical presence &#8212; a faith that exceeds Israel&#8217;s. The Jewish elders&#8217; willingness to plead for a Gentile&#8217;s household reflects the unexpected coalitions the kingdom creates.</p>",
    "4": "<p>&#8220;This man deserves to have you do this&#8221; &#8212; the elders&#8217; appeal to the centurion&#8217;s merit (<em>axios</em>) is ironically countered by the centurion&#8217;s own self-assessment (v.6: &#8220;I do not deserve to have you come under my roof&#8221;). The contrast between human declarations of merit and the centurion&#8217;s own humility is the Lukan pattern: those who declare themselves unworthy are the ones who receive; those who assert their worthiness are contrasted with those who receive grace. The centurion&#8217;s humility is itself the ground of Christ&#8217;s favor.</p>",
    "5": "<p>&#8220;He loves our nation and has built our synagogue&#8221; &#8212; the centurion&#8217;s love for Israel and his patronage of their worship anticipates the Gentile God-fearers of Acts (Cornelius, Acts 10:2: &#8220;he gave generously to those in need and prayed to God regularly&#8221;). The type: the Gentile who honors Israel&#8217;s God prefigures the Gentile mission in which non-Jews who feared God were the first recipients of the gospel. The centurion is a Cornelius-prototype, and his encounter with Jesus is a type of Acts 10.</p>",
    "6": "<p>&#8220;Lord, don&#8217;t trouble yourself, for I do not deserve to have you come under my roof&#8221; &#8212; the centurion&#8217;s self-assessment as unworthy is the model of the approach to Christ: not assertion of merit but acknowledgment of unworthiness. The <em>Kyrie</em> (Lord) address identifies Christ with divine authority &#8212; the centurion understands that he is addressing one whose presence in his house would constitute a kind of holy condescension, analogous to the divine presence descending to the Tabernacle (Exod 40:34&#8211;35).</p>",
    "7": "<p>&#8220;But say the word, and my servant will be healed&#8221; &#8212; the centurion&#8217;s faith in the healing power of Christ&#8217;s word alone is the highest statement of Christological faith in the Galilean ministry. The word that heals is the divine creative word (Gen 1; Ps 33:9: &#8220;he spoke, and it came to be; he commanded, and it stood firm&#8221;). The centurion recognizes in Jesus the one whose word carries divine authority across space &#8212; the sovereign word that creation itself obeys.</p>",
    "8": "<p>The centurion&#8217;s analogy from military authority to divine authority is the logic of the incarnation. A soldier obeys without knowing all the reasons; Jesus&#8217;s servant (creation, disease, death) obeys his word because of the authority behind it. The centurion has discerned something the disciples are still learning: Christ commands not by requesting but by the inherent authority of the one sent by the Father (John 5:19: &#8220;the Son can do nothing by himself; he can do only what he sees his Father doing&#8221;). His word carries the Father&#8217;s authority.</p>",
    "9": "<p>&#8220;I tell you, I have not found such great faith even in Israel&#8221; &#8212; the commendation of Gentile faith exceeding Jewish faith is both a Christological verdict and a prophetic sign. It fulfills Isa 49:6 (the Servant as &#8220;a light for the Gentiles&#8221;) and anticipates Luke&#8217;s two examples of Gentile/outsider favor in Jesus&#8217;s Nazareth sermon (4:25&#8211;27: the widow of Zarephath and Naaman the Syrian). The Gentile centurion&#8217;s faith is the first fruit of the universal harvest that Christ came to gather.</p>",
    "10": "<p>&#8220;The men who had been sent returned to the house and found the servant well (<em>hygiainonta</em>, in health)&#8221; &#8212; the healing in absentia accomplished by Jesus&#8217;s word is confirmed. The sign value is high: Jesus heals across distance by speech alone, demonstrating the omnipresent power of his word. The word-healing prefigures the cosmic scope of his lordship: in his resurrection and ascension, Christ&#8217;s word goes out to all nations (Matt 28:18&#8211;20: &#8220;all authority in heaven and on earth has been given to me&#8221;).</p>",
    "11": "<p>Nain (&#8220;beauty&#8221; in Hebrew) was a village in lower Galilee. Jesus arriving at the town gate just as a funeral procession is leaving is a providential encounter &#8212; Luke frames it as the Lord meeting death on its way out. The geographical movement (Jesus coming to the gate) mirrors the theological movement of the incarnation: the Author of life (Acts 3:15) enters the world to meet and reverse the procession of death that began in Gen 3 with Adam&#8217;s expulsion from the garden of life.</p>",
    "12": "<p>&#8220;The only son of his mother, and she was a widow&#8221; &#8212; the double vulnerability of the woman (widow + only son) intensifies the pathos and the Christological sign. The widow&#8217;s situation echoes the widow of Zarephath (1 Kgs 17:17&#8211;24), whose only son Elijah raised &#8212; and Jesus cites this very story in 4:25&#8211;26. Luke signals the Elijah typology: Jesus is the greater Elijah (the eschatological prophet like Moses, Deut 18:15), whose raising of the widow&#8217;s son exceeds even the Elijah prototype.</p>",
    "13": "<p>&#8220;When the Lord saw her, his heart went out to her (<em>esplanchnisthē</em>) and he said: Don&#8217;t cry&#8221; &#8212; divine compassion (<em>splanchna</em>, the Hebrew <em>rahamim</em> of God&#8217;s maternal mercy; cf. Isa 49:15) is the motivation of the miracle. Luke uniquely uses the title &#8220;the Lord&#8221; (<em>ho Kyrios</em>) for Jesus in narrative (not in dialogue) here &#8212; signaling that the compassion of the Lord of creation is personally present, acting on the widow&#8217;s behalf. The command &#8220;don&#8217;t cry&#8221; is eschatological: the Lord of life reverses what death produces.</p>",
    "14": "<p>&#8220;Young man, I say to you, get up!&#8221; (<em>neaniske, soi leg&#333;, egerthēti</em>) &#8212; the resurrection command. <em>Egerthēti</em> (the passive imperative of <em>egeir&#333;</em>) is the resurrection verb used throughout the NT for Christ&#8217;s own raising (Luke 24:6; Acts 3:15; Rom 4:25). Touching the bier made Jesus ritually unclean (Num 19:11); his willingness to touch death to reverse it foreshadows the cross, where he enters fully into death to bring resurrection. The &#8220;I say to you&#8221; (not &#8220;in God&#8217;s name&#8221;) indicates self-authority, not prophetic agency.</p>",
    "15": "<p>&#8220;The dead man sat up and began to talk, and Jesus gave him back to his mother&#8221; &#8212; the precise echo of 1 Kgs 17:23 (&#8220;Elijah picked up the child and carried him down from the room into the house. He gave him to his mother and said, &#8216;Look, your son is alive!&#8217;&#8221;). Luke&#8217;s deliberate echo establishes the Elijah typology while exceeding it: Elijah prayed three times and stretched himself over the boy; Jesus speaks a single word of command. The comparison highlights the eschatological upgrade: the greater prophet is here.</p>",
    "16": "<p>&#8220;A great prophet has appeared among us. God has come to help his people&#8221; &#8212; the crowd&#8217;s twofold response is both accurate and insufficient. &#8220;Great prophet&#8221; is true but partial (Elijah, Moses, one of the ancient prophets &#8212; cf. 9:8, 19); &#8220;God has come to help his people&#8221; (<em>epeskepsato</em>, God has visited) is the deeper truth. <em>Episkopē</em> (divine visitation) is the language of Exod 4:31 (Israel recognized God&#8217;s visitation in Moses) and Ps 80:14 (&#8220;look down from heaven and see&#8221;). The crowd partially perceives: this is indeed the divine visitation, but in a person, not a prophet.</p>",
    "17": "<p>The news spreading throughout Judea and the surrounding country mirrors the spreading of the Servant&#8217;s fame in Isa 52:13&#8211;15 (&#8220;his appearance was so disfigured&#8230; but he will sprinkle many nations&#8221;). The report of Jesus&#8217;s works reaches to the regions that will be evangelized in Acts &#8212; the spreading news is the pre-evangelism that prepares the way. Every miracle-report is a seed of the resurrection proclamation: the one who raises the dead in Galilee will himself be raised in Jerusalem.</p>",
    "18": "<p>John&#8217;s disciples reporting to him &#8220;all these things&#8221; sets up the pivotal question of v.19. John in prison (3:20) is the type of the suffering precursor: Elijah (who prefigures John) suffered under Ahab and Jezebel, yet his work preceded the new order. John&#8217;s imprisonment does not stop the mission &#8212; his disciples continue as intermediaries between John and Jesus. The question John sends is the theological hinge of Luke 7: the imprisoned forerunner asking the Messiah to confirm his identity.</p>",
    "19": "<p>&#8220;Are you the one who is to come, or should we expect someone else?&#8221; &#8212; John&#8217;s question has exercised interpreters: is it doubt, or is John teaching his disciples to seek their answer from Jesus? Either way, the question is the right one, and Jesus&#8217;s answer is definitive. &#8220;The one who is to come&#8221; (<em>ho erchomenos</em>) is the technical messianic title &#8212; the coming one of Ps 118:26, cited at the Triumphal Entry (19:38). John&#8217;s question frames the whole subsequent narrative as the answer to: is this the Messiah?</p>",
    "20": "<p>The repetition of John&#8217;s question (&#8220;Are you the one who is to come, or should we expect someone else?&#8221;) ensures the question is heard plainly by Jesus and by Luke&#8217;s reader. The directness &#8212; John sends his disciples to ask Jesus personally &#8212; mirrors the directness of the Christological question the whole Gospel asks. Luke frames Jesus&#8217;s entire ministry as the answer to this question: every healing, every teaching, every exorcism is evidence for the answer Jesus gives in v.22.</p>",
    "21": "<p>&#8220;At that very time Jesus cured many who had diseases, sicknesses and evil spirits, and gave sight to many who were blind&#8221; &#8212; the timing is crucial: Jesus answers John&#8217;s question not with a speech but with deeds. The healings at the moment of John&#8217;s question are themselves the answer, the living fulfillment of Isaiah&#8217;s signs. This is the epistemological method of the Gospels: Christ&#8217;s identity is verified by his works (John 5:36: &#8220;the works that the Father has given me to finish &#8212; the very works I am doing &#8212; testify that the Father has sent me&#8221;).</p>",
    "23": "<p>&#8220;Blessed is anyone who does not stumble on account of me&#8221; &#8212; the beatitude after the Isaianic sign-list is a warning as well as a blessing. The &#8220;stumbling block&#8221; (<em>skandalon</em>) is the offense of the Christ who does not match expectations: he comes as a servant who heals and preaches rather than as a warrior-king who conquers. Isa 8:14 describes YHWH himself as &#8220;a stone that causes men to stumble and a rock that makes them fall.&#8221; Christ as the fulfillment of both the Servant and the divine Stumbling-Stone is the crux of the Gospel&#8217;s challenge.</p>",
    "24": "<p>&#8220;What did you go out into the wilderness to see? A reed shaken by the wind?&#8221; &#8212; Jesus&#8217;s eulogy of John begins by contrasting John with the unstable, the decorative, and the comfortable. The wilderness where John operated is the wilderness of Isa 40:3 (&#8220;a voice of one calling in the wilderness: Prepare the way for the LORD&#8221;). John in the wilderness is the herald who precedes the Lord&#8217;s advent &#8212; not a reed shaken by political winds but a fixed prophetic voice calling Israel to prepare for the visitation of YHWH.</p>",
    "25": "<p>&#8220;If not, what did you go out to see? A man dressed in fine clothes? No, those who wear expensive clothes and indulge in luxury are in palaces&#8221; &#8212; John&#8217;s camel-hair clothing and locust diet (mentioned in Mark 1:6) are the marks of the prophetic counter-culture. The contrast with palatial luxury is also a contrast with Herod (in whose court John will be killed): the prophet who prepares the way for the Servant-Messiah wears the garb of the prophetic tradition (Zech 13:4), not the clothing of earthly kings.</p>",
    "26": "<p>&#8220;A prophet? Yes, I tell you, and more than a prophet&#8221; &#8212; Jesus&#8217;s confirmation that John is more than a prophet clarifies the prophetic category itself. The OT prophets pointed forward; John is the hinge &#8212; the last prophet who also functions as the forerunner at the moment of fulfillment. &#8220;More than a prophet&#8221; because he is the living transition point between promise and fulfillment, standing inside the stream of prophecy while pointing to the one in whom all prophecy is realized.</p>",
    "27": "<p>&#8220;This is the one about whom it is written: I will send my messenger ahead of you, who will prepare your way before you&#8221; &#8212; a direct citation of Mal 3:1 (with influence from Exod 23:20), identifying John as the fulfillment of the Malachi messenger prophecy. The &#8220;you&#8221; addressed in Mal 3:1 is YHWH himself (&#8220;who will prepare the way before me&#8221;), which Luke rephrases as &#8220;before you&#8221; &#8212; making Jesus the Lord YHWH whose way John prepares. The citation is one of Luke&#8217;s most direct identifications of Jesus with YHWH.</p>",
    "28": "<p>&#8220;I tell you, among those born of women there is no one greater than John; yet the one who is least in the kingdom of God is greater than he&#8221; &#8212; the paradox reveals the eschatological divide. John is the greatest of the old order &#8212; the culminating prophet who stands on the threshold; but the kingdom inaugurated in Jesus surpasses the whole previous era. Even the least in the kingdom (who has received the Spirit, the new covenant heart, the forgiveness of sins in Christ&#8217;s name) stands on the far side of the divide that John could only approach. The kingdom is not a better version of the prophetic era; it is a new creation.</p>",
    "29": "<p>&#8220;All the people, even the tax collectors, when they heard Jesus&#8217;s words, acknowledged that God&#8217;s way was right, because they had been baptized by John&#8221; &#8212; John&#8217;s baptism of repentance prepared the people to receive Jesus&#8217;s proclamation. The tax collectors who received John&#8217;s baptism are the type of those who receive Christ&#8217;s grace: the marginalized, the sinners, those who know their need. Their acknowledgment of God&#8217;s justice (<em>dikaioō ton theon</em>) is the first step toward justification &#8212; the recognition that God is right and they are not.</p>",
    "30": "<p>&#8220;But the Pharisees and the experts in the law rejected God&#8217;s purpose for themselves, because they had not been baptized by John&#8221; &#8212; the irony is sharp: those who were the guardians of God&#8217;s purpose rejected it, while the despised tax collectors embraced it. The Pharisees&#8217; refusal of John&#8217;s baptism is also a refusal of Christ, since John&#8217;s baptism was preparation for the coming one. The self-sufficiency that makes baptism unnecessary is the same self-sufficiency that makes the cross unnecessary &#8212; and thus excludes from its benefits.</p>",
    "31": "<p>&#8220;To what can I compare the people of this generation?&#8221; &#8212; the parable of the children in the marketplace addresses the generation that witnessed both John and Jesus and rejected both. The &#8220;this generation&#8221; language throughout Luke (7:31; 9:41; 11:29, 50&#8211;51; 17:25) marks the generation that faces the decisive Christological choice: to receive or reject the Son of Man. The parable-form of the comparison is itself a Christological act: Jesus as the teacher of parables (Ps 78:2) interprets the generation to itself.</p>",
    "32": "<p>&#8220;They are like children sitting in the market-place and calling out: We played the pipe for you, and you did not dance; we sang a dirge, and you did not weep&#8221; &#8212; neither the joy of the gospel (John&#8217;s baptism of repentance leading to life) nor the mourning of judgment (the dirge) moved the generation. Christ as the one whose coming is the occasion for both joy (the Bridegroom&#8217;s arrival, 5:34) and mourning (the call to repentance) is rejected by those who refuse both categories. The marketplace complaint reveals the generation&#8217;s fundamental uncharity.</p>",
    "33": "<p>&#8220;For John the Baptist came neither eating bread nor drinking wine, and you say, He has a demon&#8221; &#8212; John&#8217;s asceticism &#8212; fasting, abstinence, wilderness discipline &#8212; is the Nazirite/Elijah pattern (Num 6; 1 Kgs 17&#8211;19). The accusation of demon-possession against ascetic fasting mirrors the accusation of demon-possession against Jesus&#8217;s exorcisms (11:15). Both John&#8217;s fasting and Jesus&#8217;s feasting are dismissed, demonstrating that the issue is not the form but the unwillingness to receive the message regardless of its packaging.</p>",
    "34": "<p>&#8220;The Son of Man came eating and drinking, and you say, Here is a glutton and a drunkard, a friend of tax collectors and sinners&#8221; &#8212; Jesus&#8217;s self-description as &#8220;friend of tax collectors and sinners&#8221; is both an accusation he accepts and a revelation of his mission. &#8220;Friend&#8221; (<em>philos</em>) is what Abraham was called (Isa 41:8; Jas 2:23: &#8220;friend of God&#8221;). Christ as the friend of sinners is the one who crossed the social, moral, and religious boundary to share the table of those excluded from the covenant community, fulfilling Isa 53:12 (&#8220;he bore the sin of many, and made intercession for the transgressors&#8221;).</p>",
    "35": "<p>&#8220;But wisdom is proved right by all her children&#8221; &#8212; the final verdict: wisdom (Christ as incarnate Wisdom, 1 Cor 1:24,30; Col 2:3) is justified by those who receive her. The &#8220;children of wisdom&#8221; are those who respond rightly &#8212; the tax collectors who repented at John&#8217;s baptism and received Jesus&#8217;s welcome. Wisdom personified in Prov 8 cries out in the marketplaces; Jesus cried out in the marketplace (so to speak) through both John and himself; wisdom&#8217;s vindication is the community of those who received both.</p>",
    "36": "<p>The Pharisee&#8217;s dinner invitation and Jesus&#8217;s acceptance establishes the setting for the most dramatic public forgiveness scene in Luke&#8217;s Gospel. Jesus accepts the invitation (as elsewhere, 19:5: &#8220;I must stay at your house today&#8221;) &#8212; his willingness to eat with Pharisees as well as tax collectors demonstrates the consistent pattern of table hospitality as the embodiment of kingdom welcome. The dinner table is the site of revelation: both the failure of Simon&#8217;s hospitality and the extravagance of the woman&#8217;s love will be displayed.</p>",
    "37": "<p>&#8220;A woman in that town who lived a sinful life learned that Jesus was eating at the Pharisee&#8217;s house, so she came there with an alabaster jar of perfume&#8221; &#8212; the woman&#8217;s identity as a public sinner and her act of bringing expensive perfume to anoint Jesus are types of the penitent&#8217;s approach to grace. The expensive perfume given without return echoes the Deuteronomic warning against half-hearted worship (Deut 15:10). Her costly gift is the act of one who has received the greater gift &#8212; forgiveness &#8212; and responds with extravagance that defies social calculation.</p>",
    "38": "<p>&#8220;She began to wet his feet with her tears and wiped them with her hair, kissed them and poured perfume on them&#8221; &#8212; a sequence of increasingly intimate acts of reverence: tears, drying with hair, kissing, anointing. Each act is a shadow of the ultimate anointing &#8212; the anointing of Jesus for burial that Mary of Bethany performs (John 12:3) before the crucifixion. The woman&#8217;s tears anticipate the mourning of the cross; her anointing prefigures the burial anointing. She performs unwittingly what the Gospel calls the disciples to understand: loving the one who goes to death for sinners.</p>",
    "39": "<p>&#8220;If this man were a prophet, he would know who is touching him and what kind of woman she is &#8212; that she is a sinner&#8221; &#8212; Simon&#8217;s reasoning fails on both counts: Jesus does know (v.40: &#8220;Jesus answered him&#8221; before Simon voiced the thought), and Simon&#8217;s assessment of the woman as merely a sinner is the assessment that the parable of the two debtors will overturn. The Pharisee&#8217;s &#8220;if this man were a prophet&#8221; is the exact opposite of the crowd&#8217;s recognition at Nain (v.16: &#8220;a great prophet has appeared among us&#8221;) &#8212; and both responses are surpassed by the truth.</p>",
    "40": "<p>&#8220;Simon, I have something to tell you&#8221; &#8212; the parable that follows is Jesus&#8217;s answer to Simon&#8217;s unspoken judgment. The willingness to address Simon&#8217;s private thought publicly demonstrates the same divine knowledge that Simon thought disqualified Jesus (v.39). Jesus speaks the parable to invite Simon into self-recognition &#8212; the same invitation that Nathan gave David with &#8220;you are the man&#8221; (2 Sam 12:7). Christ as the parabolist who brings the heart&#8217;s hidden self-righteousness to light is doing what only the searcher of hearts can do (Ps 139; Jer 17:10).</p>",
    "41": "<p>The parable of the two debtors &#8212; one owing five hundred denarii, one fifty &#8212; is a Christological parable about grace and gratitude. The economic framework (debt, forgiveness, love) mirrors the theological framework of the atonement: all have debts they cannot pay (Rom 3:23: &#8220;all have sinned&#8221;), and the forgiveness is unilateral. The two debtors represent the woman (large debt) and Simon (small debt in his own estimation) &#8212; and the parable&#8217;s reversal (the greater debt produces greater love) inverts the social hierarchy of the dinner party.</p>",
    "42": "<p>&#8220;Neither of them had the money to pay him back, so he forgave the debts of both&#8221; &#8212; the forgiveness is freely given to both, based entirely on the creditor&#8217;s decision, not on any merit of the debtors. The theme of unconditional forgiveness is grounded in the cross: &#8220;while we were still sinners, Christ died for us&#8221; (Rom 5:8). The moneylender who forgives without payment is the shadow of the God who justifies the ungodly (Rom 4:5). The parable teaches that the objective reality of forgiveness precedes and produces the subjective experience of gratitude and love.</p>",
    "43": "<p>&#8220;I suppose the one who had the bigger debt forgiven&#8221; &#8212; Simon&#8217;s grudging answer (&#8220;I suppose,&#8221; <em>hypolamban&#333;</em>) is a reluctant logic that his own estimate of himself will not follow. The comparison between the woman&#8217;s lavish love and Simon&#8217;s minimal hospitality will be made explicit in vv.44&#8211;46. Simon is invited by his own answer to see himself as the debtor who loves little because he believes himself forgiven little &#8212; the parable&#8217;s judgment is absorbed through Simon&#8217;s own words.</p>",
    "44": "<p>&#8220;Do you see this woman? I came into your house. You did not give me any water for my feet, but she wet my feet with her tears and wiped them with her hair&#8221; &#8212; the contrast between Simon&#8217;s failure of basic hospitality and the woman&#8217;s extravagance exposes Simon&#8217;s heart. In the honor-shame culture, failing to provide water for the guest&#8217;s feet was a notable slight. The woman&#8217;s tears replacing the water is an act of self-humiliation that surpasses all social obligation. Christ who received such extravagant devotion will himself wash his disciples&#8217; feet (John 13:5) &#8212; the Lord enacting the servant&#8217;s role.</p>",
    "45": "<p>&#8220;You did not give me a kiss, but this woman, from the time I entered, has not stopped kissing my feet&#8221; &#8212; the kiss of greeting was standard hospitality (cf. Rom 16:16: &#8220;greet one another with a holy kiss&#8221;); its absence from Simon signals cool formality rather than warm welcome. The woman&#8217;s continuous kissing of his feet is the posture of a penitent before a king &#8212; the devotion of one who knows she stands before grace itself. The contrast continues to expose the heart: formal observance vs. love born of received forgiveness.</p>",
    "46": "<p>&#8220;You did not put oil on my head, but she has poured perfume on my feet&#8221; &#8212; anointing the head of a guest with oil was a mark of honor (Ps 23:5: &#8220;you anoint my head with oil&#8221;; Ps 133:2). Simon&#8217;s omission is the third mark of minimal hospitality. The woman&#8217;s pouring expensive perfume on his feet is the extravagant reversal &#8212; she gives what is costlier (perfume vs. oil) in the more humble place (feet vs. head). The inversion encodes the kingdom&#8217;s logic: the one who humbles herself before Christ is the one who most honors him.</p>",
    "47": "<p>&#8220;Therefore, I tell you, her many sins have been forgiven &#8212; as her great love has shown. But whoever has been forgiven little loves little&#8221; &#8212; the declaration of forgiveness is retroactive: the woman&#8217;s love demonstrates prior forgiveness, not that her love caused it. This is the crucial distinction: forgiveness precedes love as the tree precedes the fruit. The parable has already established this (v.42: &#8220;he forgave the debts of both&#8221;). The Christological core: Jesus speaks as the one who has the authority to forgive sins &#8212; which the guests immediately question in v.49.</p>",
    "48": "<p>&#8220;Then Jesus said to her: Your sins are forgiven&#8221; &#8212; the direct declarative forgiveness. This is the same formula used in the paralytic&#8217;s healing (5:20: &#8220;your sins are forgiven&#8221;), which triggered the scribes&#8217; accusation of blasphemy (5:21). The authority Jesus exercises here is the authority that belongs to God alone (Isa 43:25: &#8220;I, even I, am he who blots out your transgressions, for my own sake, and remembers your sins no more&#8221;). The woman&#8217;s sins are forgiven by the one who is the incarnation of the divine forgiver.</p>",
    "49": "<p>&#8220;Who is this who even forgives sins?&#8221; &#8212; the table guests&#8217; question is the central Christological question of the passage (and of the whole Gospel). Their question implies the correct theological premise (only God forgives sins, Ps 103:3; Isa 43:25) while failing to draw the correct Christological conclusion (therefore, this man is God in human form). The question &#8220;who is this?&#8221; echoes the storm-disciples&#8217; question (8:25: &#8220;who is this? He commands even the winds and the water&#8221;) &#8212; the Gospel invites its readers to answer what the characters cannot.</p>",
    "50": "<p>&#8220;Your faith has saved you (<em>ses&#333;ken</em>); go in peace&#8221; &#8212; the salvation-word and the shalom-blessing close the passage with the double gift: salvation (comprehensive deliverance from sin and its consequences) and peace (the <em>shalom</em> of restored relationship with God, Isa 57:19: &#8220;peace to those far and near&#8221;). The faith that saves is trust in the person of Jesus &#8212; the woman did not articulate a theology; she acted in love toward the one who had forgiven her. The peace Christ pronounces is the peace that the cross purchases (Col 1:20: &#8220;making peace through his blood, shed on the cross&#8221;).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, DATA)
    merge_comm(existing, FILL_CH6)
    merge_comm(existing, FILL_CH7)
